    if (!audioFile) { notify('error','Upload an audio file first.'); return; }
    setTranscribingAudio(true); setAudioTranscript('');
    notify('success','Uploading to transcription service… please wait (1–2 min).');
    const cancelSource = axios.CancelToken.source();
    audioRef.current = { cancel: ()=>cancelSource.cancel('Cancelled') };
    try {
      const fd = new FormData();
      fd.append('file', audioFile);
      fd.append('language', speechToCode(audioLang));
      const res = await axios.post(`${API}/transcribe`, fd, {
        headers:{'Content-Type':'multipart/form-data'},
        timeout:600000, cancelToken:cancelSource.token
      });
      if (res.data?.transcript) {
        setAudioTranscript(res.data.transcript);
        setNote(p=>({...p, content:res.data.transcript}));
        notify('success','Transcription complete! ✅');
      } else notify('error','No transcription returned.');
    } catch(e) {
      if(axios.isCancel(e)) notify('error','Transcription cancelled.');
      else notify('error','Transcription failed: '+(e.response?.data?.message||e.message));
    } finally { setTranscribingAudio(false); audioRef.current=null; }
  };

  // ── SCREEN RECORD ──
  const startScreenRecord = async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video:{mediaSource:'screen'}, audio:true
      });
      screenRecRef.current = stream;
      chunksRef.current = [];
      setScreenRecTranscript('');
      setVideoStatus('🔴 Recording… navigate to your content. Come back and press Stop when done.');

      const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')
        ? 'video/webm;codecs=vp9,opus'
        : 'video/webm';

      const recorder = new MediaRecorder(stream, {mimeType});
      mediaRecRef.current = recorder;

      recorder.ondataavailable = e => {
        if (e.data?.size>0) chunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        setScreenRec(false);
        stream.getTracks().forEach(t=>t.stop());
        if (chunksRef.current.length===0) {
          setVideoStatus(''); notify('error','No data recorded.'); return;
        }
        setVideoStatus('⏳ Processing recording… sending for transcription');
        const blob = new Blob(chunksRef.current, {type:mimeType});
        const file = new File([blob],'screen-recording.webm',{type:mimeType});
        notify('success',`Recording (${(blob.size/1024/1024).toFixed(1)}MB) uploading for transcription…`);
        try {
          const fd = new FormData();
          fd.append('file', file);
          fd.append('language', speechToCode(videoLang));
          const res = await axios.post(`${API}/transcribe`, fd, {
            headers:{'Content-Type':'multipart/form-data'}, timeout:600000
          });
          if (res.data?.transcript) {
            setScreenRecTranscript(res.data.transcript);
            setNote(p=>({...p, content:res.data.transcript}));
            setVideoStatus('');
            notify('success','Screen recording transcribed! ✅');
          } else {
            setVideoStatus(''); notify('error','No transcript. Recording may have no speech.');
          }
        } catch(e) {
          setVideoStatus(''); notify('error','Transcription failed: '+(e.response?.data?.message||e.message));
        }
        chunksRef.current=[];
      };

      recorder.start(1000);
      setScreenRec(true);
      setNote(p=>({...p,source:'screen'}));
      stream.getVideoTracks()[0].onended = ()=>{ if(recorder.state!=='inactive') recorder.stop(); };
      notify('success','🖥️ Recording started! Navigate anywhere — come back and click Stop when done.');
    } catch(e) {
      if(e.name==='NotAllowedError') notify('error','Screen sharing cancelled.');
      else notify('error','Screen record failed: '+e.message);
      setScreenRec(false); setVideoStatus('');
    }
  };

  const stopScreenRecord = () => {
